const { chromium } = require('playwright');
(async() => {
  const widths = [390, 768, 1280];
  for (const width of widths) {
    const browser = await chromium.launch({ headless: true });
    const page = await browser.newPage({ viewport: { width, height: 900 } });
    await page.goto('http://127.0.0.1:4174/', { waitUntil: 'networkidle' });
    const data = await page.evaluate(() => {
      const hero = document.querySelector('.hero, [data-section="hero"], header');
      const portfolioSection = document.getElementById('portfolio') || [...document.querySelectorAll('section')].find(s => s.textContent.includes('Explore four directions'));
      const cards = portfolioSection ? Array.from(portfolioSection.querySelectorAll('a, article, li, div')).filter(el => el.textContent && /Prospex|Presage|Astron|King Seiko/.test(el.textContent)) : [];
      const matrix = document.getElementById('matrix') || [...document.querySelectorAll('section')].find(s => s.textContent.includes('How the four references operate in reality'));
      const featuredHeadings = Array.from(document.querySelectorAll('h1,h2,h3')).map(el => el.textContent.trim()).filter(Boolean);
      const bodyOverflow = document.documentElement.scrollWidth > window.innerWidth;
      const anchors = Array.from(document.querySelectorAll('a[href^="#"]')).map(a => ({text:a.textContent.trim(), href:a.getAttribute('href')}));
      const buttons = Array.from(document.querySelectorAll('button')).map(b => b.textContent.trim());
      const imgAlts = Array.from(document.querySelectorAll('img')).map(img => img.getAttribute('alt'));
      const heroStyle = hero ? getComputedStyle(hero) : null;
      return {
        title: document.title,
        width: window.innerWidth,
        bodyOverflow,
        anchors,
        buttons,
        imgAlts,
        headings: featuredHeadings.slice(0, 20),
        heroGridCols: heroStyle?.gridTemplateColumns || null,
        heroDisplay: heroStyle?.display || null,
        portfolioText: portfolioSection?.textContent?.slice(0,300) || null,
        cardMatches: cards.length,
        matrixText: matrix?.textContent?.slice(0,240) || null,
      };
    });
    console.log('WIDTH', width, JSON.stringify(data));
    await browser.close();
  }
})();
