const { chromium } = require('playwright');
(async() => {
  const widths = [390, 768, 1280];
  for (const width of widths) {
    const browser = await chromium.launch({ headless: true });
    const page = await browser.newPage({ viewport: { width, height: 900 } });
    await page.goto('http://127.0.0.1:4174/', { waitUntil: 'networkidle' });
    const data = await page.evaluate(() => {
      const q = (sel) => document.querySelector(sel);
      const style = (el) => el ? getComputedStyle(el) : null;
      const hero = q('.hero-panel');
      const portfolioGrid = q('.portfolio-grid');
      const featureList = document.querySelectorAll('.feature-card');
      const matrixRows = document.querySelectorAll('.matrix-row');
      const matrixValues = q('.matrix-values');
      const bodyOverflow = document.documentElement.scrollWidth > window.innerWidth;
      const portfolioLinks = Array.from(document.querySelectorAll('.portfolio-link')).map((el) => ({
        text: el.innerText.replace(/\s+/g, ' ').trim(),
        rect: { x: el.getBoundingClientRect().x, y: el.getBoundingClientRect().y, w: el.getBoundingClientRect().width, h: el.getBoundingClientRect().height }
      }));
      const firstFeature = q('.feature-card');
      const cardsOnFirstRow = portfolioLinks.filter((a) => a.rect.y < (portfolioLinks[0]?.rect.y ?? 0) + 10).length;
      return {
        width: window.innerWidth,
        bodyOverflow,
        heroCols: style(hero)?.gridTemplateColumns,
        heroChildren: hero ? Array.from(hero.children).map(el => ({cls: el.className, y: el.getBoundingClientRect().y, x: el.getBoundingClientRect().x, w: el.getBoundingClientRect().width})) : [],
        portfolioCols: style(portfolioGrid)?.gridTemplateColumns,
        portfolioCount: portfolioLinks.length,
        portfolioFirstRowCount: cardsOnFirstRow,
        featureCardCount: featureList.length,
        featureCols: firstFeature ? style(firstFeature).gridTemplateColumns : null,
        matrixRowCols: matrixRows[1] ? style(matrixRows[1]).gridTemplateColumns : null,
        matrixValuesCols: style(matrixValues)?.gridTemplateColumns,
        hasHorizontalScroll: Array.from(document.querySelectorAll('*')).some(el => el.scrollWidth > el.clientWidth + 1 && style(el)?.overflowX !== 'hidden'),
        anchorText: Array.from(document.querySelectorAll('a[href^="#"]')).map(a => a.textContent.trim()),
      };
    });
    console.log(JSON.stringify(data));
    await browser.close();
  }
})();
